'use strict';

const sgMail = require('@sendgrid/mail');
const twilio = require('twilio');

let initialized = false;
let twilioClient;

function getEnv(name, required = true) {
  const value = process.env[name];
  if (required && (!value || !String(value).trim())) {
    throw new Error(`Missing required environment variable: ${name}`);
  }
  return value;
}

function initializeClients() {
  if (initialized) return;

  const sendGridApiKey = getEnv('SENDGRID_API_KEY');
  const twilioAccountSid = getEnv('TWILIO_ACCOUNT_SID');
  const twilioAuthToken = getEnv('TWILIO_AUTH_TOKEN');

  sgMail.setApiKey(sendGridApiKey);
  twilioClient = twilio(twilioAccountSid, twilioAuthToken);

  initialized = true;
}

function jsonResponse(res, status, body) {
  res.status(status).json(body);
}

function isValidEmail(email) {
  return typeof email === 'string' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
}

function isValidPhone(phone) {
  return typeof phone === 'string' && /^\+[1-9]\d{7,14}$/.test(phone);
}

async function sendEmail(payload) {
  const from = payload.from || getEnv('SENDGRID_FROM_EMAIL');
  const msg = {
    to: payload.to,
    from,
    subject: payload.subject,
    text: payload.text,
    html: payload.html,
    cc: payload.cc,
    bcc: payload.bcc,
    replyTo: payload.replyTo,
    attachments: payload.attachments
  };

  await sgMail.send(msg);
  return {
    channel: 'email',
    delivered: true,
    to: payload.to
  };
}

async function sendSms(payload) {
  const from = payload.from || getEnv('TWILIO_FROM_NUMBER');
  const message = await twilioClient.messages.create({
    body: payload.body,
    from,
    to: payload.to
  });

  return {
    channel: 'sms',
    delivered: true,
    to: payload.to,
    sid: message.sid,
    status: message.status
  };
}

function validateEmailPayload(email) {
  if (!email) return null;
  if (!email.to || !isValidEmail(email.to)) {
    throw new Error('Invalid email.to');
  }
  if (!email.subject || typeof email.subject !== 'string') {
    throw new Error('Invalid email.subject');
  }
  if ((!email.text || typeof email.text !== 'string') && (!email.html || typeof email.html !== 'string')) {
    throw new Error('Email requires text or html content');
  }
  if (email.from && !isValidEmail(email.from)) {
    throw new Error('Invalid email.from');
  }
  return email;
}

function validateSmsPayload(sms) {
  if (!sms) return null;
  if (!sms.to || !isValidPhone(sms.to)) {
    throw new Error('Invalid sms.to. Use E.164 format, e.g. +15551234567');
  }
  if (!sms.body || typeof sms.body !== 'string') {
    throw new Error('Invalid sms.body');
  }
  if (sms.from && !isValidPhone(sms.from)) {
    throw new Error('Invalid sms.from. Use E.164 format, e.g. +15551234567');
  }
  return sms;
}

exports.deliverMessage = async (req, res) => {
  try {
    initializeClients();

    if (req.method !== 'POST') {
      return jsonResponse(res, 405, { error: 'Method Not Allowed' });
    }

    const contentType = req.get('content-type') || '';
    if (!contentType.includes('application/json')) {
      return jsonResponse(res, 415, { error: 'Content-Type must be application/json' });
    }

    const body = req.body || {};
    const email = validateEmailPayload(body.email);
    const sms = validateSmsPayload(body.sms);

    if (!email && !sms) {
      return jsonResponse(res, 400, { error: 'Provide at least one of: email or sms' });
    }

    const tasks = [];
    if (email) {
      tasks.push(
        sendEmail(email).then(
          result => ({ success: true, result }),
          err => ({ success: false, channel: 'email', error: err.message })
        )
      );
    }

    if (sms) {
      tasks.push(
        sendSms(sms).then(
          result => ({ success: true, result }),
          err => ({ success: false, channel: 'sms', error: err.message })
        )
      );
    }

    const results = await Promise.all(tasks);
    const allSucceeded = results.every(r => r.success);

    return jsonResponse(res, allSucceeded ? 200 : 207, {
      ok: allSucceeded,
      results
    });
  } catch (err) {
    const status = /Missing required environment variable/.test(err.message) ? 500 : 400;
    return jsonResponse(res, status, {
      ok: false,
      error: err.message
    });
  }
};